INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES (1, 19430025, 0, 122511, 1, "ずいぶんと色々なものが流れているね。\nここがプールでないなら、\n魚が潜んでいそうだけど…", 943, 0, 0, 7, 11);
INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES ("", 19430026, "", 0, "", "", 943, "", "", "", 91);
