INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES (1, 19430030, 0, 122511, 1, "そうだ、この流れに身を任せることで\n渓流の魚たちの気持ちを学べば、\n次の釣りに活かせるかもしれないな。", 943, 0, 0, 6, 11);
INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES ("", 19430031, "", 0, "", "", 943, "", "", "", 91);
