INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES (1, 19450033, 0, 122611, 1, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 945, 0, 0, 5, 11);
INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES ("", 19450034, "", 0, "", "", 945, "", "", "", 91);
