INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES (1, 19450037, 0, 110411, 0.5, "わかったよ。あたしがついてって\nかわりに食ってやるから…\n他のおかずは自信作なんだろ？\nほら、早く行くぞ！", 945, 0, 0, 9, 11);
INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES ("", 19450038, "", 0, "", "", 945, "", "", "", 91);
